import{join as r}from"node:path";export const CONFIG_FILE="tavernos.json",BOOKS_DIR="books",PERSONAS_DIR="personas",LOREBOOK_DIR="lorebook",CHAPTERS_DIR="chapters",STORY_DIR="story",EXPORTS_DIR="exports";export function bookDir(o,t){return r(o,BOOKS_DIR,t)}export function chaptersDir(o,t){return r(bookDir(o,t),CHAPTERS_DIR)}export function chapterFileName(o){return`${String(o).padStart(3,"0")}.json`}
